Greedy insertion with cost-delta evaluation across all feasible positions in existing non-empty assigns, falling back to empty assign creation when needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for orderIdx := range oris {
		bestAssignIdx := -1
		bestCostDelta := 1e100
		originalCosts := make([]float64, MAXASSIGNS)
		for i := 0; i < dispatch.AssignsLen; i++ {
			originalCosts[i] = dispatch.Assigns[i].Cost
			id := total_ship + orderIdx
			savedState := dispatch.Assigns[i]
			if dispatch.Assigns[i].AddShip(id, oris[orderIdx], dess[orderIdx]) {
				dispatch.Assigns[i].GenRoute()
				if dispatch.Assigns[i].Cost >= 0 {
					costDelta := dispatch.Assigns[i].Cost - originalCosts[i]
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestAssignIdx = i
					}
				}
				dispatch.Assigns[i] = savedState
				dispatch.Assigns[i].GenRoute()
			}
		}
		fallbackUsed := false
		if bestAssignIdx == -1 {
			if dispatch.AssignsLen < MAXASSIGNS {
				bestAssignIdx = dispatch.AssignsLen
				fallbackUsed = true
			} else {
				for i := 0; i < MAXASSIGNS; i++ {
					savedState := dispatch.Assigns[i]
					id := total_ship + orderIdx
					if dispatch.Assigns[i].AddShip(id, oris[orderIdx], dess[orderIdx]) {
						dispatch.Assigns[i].GenRoute()
						if dispatch.Assigns[i].Cost >= 0 {
							costDelta := dispatch.Assigns[i].Cost - originalCosts[i]
							if costDelta < bestCostDelta {
								bestCostDelta = costDelta
								bestAssignIdx = i
							}
						}
						dispatch.Assigns[i] = savedState
						dispatch.Assigns[i].GenRoute()
					}
				}
			}
		}
		if bestAssignIdx == -1 && dispatch.AssignsLen < MAXASSIGNS {
			bestAssignIdx = dispatch.AssignsLen
			fallbackUsed = true
		}
		if bestAssignIdx >= 0 {
			id := total_ship + orderIdx
			if fallbackUsed {
				newAssign := Assign{}
				newAssign.AddShip(id, oris[orderIdx], dess[orderIdx])
				newAssign.GenRoute()
				if newAssign.Cost >= 0 {
					dispatch.Assigns[dispatch.AssignsLen] = newAssign
					dispatch.AssignsLen++
				}
			} else {
				dispatch.Assigns[bestAssignIdx].AddShip(id, oris[orderIdx], dess[orderIdx])
				dispatch.Assigns[bestAssignIdx].GenRoute()
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

